import React from "react";

function CourseCard({course}) {
  return (
    <div style={{
      border:"1px solid #ddd",
      padding:"20px",
      width:"250px",
      borderRadius:"10px"
    }}>
      <h3>{course.title}</h3>
      <p>{course.platform}</p>
      <p>⭐ {course.rating}</p>

      <a href={course.url}>Go to course</a>
    </div>
  );
}

export default CourseCard;
